using dk.gi.app.ejendom.tjekejerskifte.Application.Abstractions; using dk.gi.app.ejendom.tjekejerskifte.Application.Models; using Gi.Batch.Shared.Logging; namespace dk.gi.app.ejendom.tjekejerskifte.Infrastructure.Crm { public sealed class EjendomTjekEjerskifteCrmGateway : IEjendomTjekEjerskifteGateway { private readonly EjendomTjekEjerskifteSettings _settings; private readonly IEjendomTjekEjerskifteWorkflow _workflow; private readonly IJobLogger _logger; public EjendomTjekEjerskifteCrmGateway(EjendomTjekEjerskifteSettings settings, IEjendomTjekEjerskifteWorkflow workflow, IJobLogger logger) { _settings = settings; _workflow = workflow; _logger = logger; } public EjendomTjekEjerskifteExecutionSummary Execute(EjendomTjekEjerskifteRequest request) { if (_settings.DryRun) _logger.Info("DRYRUN-mode aktiv. Kører lokal Dataverse-scan og payload-dannelse uden Service Bus-publicering."); else _logger.Info("RUN-mode aktiv. Kører lokal Dataverse-scan og publicerer tjekejerskifte-job til Service Bus."); return _workflow.Execute(request); } } }
